function calculateErrorRate(logs: Log[], now: number): number {
  const windowSize = 300;
  let total = 0;
  let errors = 0;
  for (let i = logs.length - 1; i >= 0; i--) {
    if (now - logs[i].timestamp > windowSize) break;
    total++;
    if (logs[i].level === 'ERROR') errors++;
  }
  return total === 0 ? 0 : errors / total;
}

