interface PipelineConfig {
  tasks: string[];
  dependencies: [string, string][]; // [task, dependsOn]
}
interface ValidationResult {
  valid: boolean;
  error?: string;
}
/**
 * 验证流水线配置
 * @param config - 流水线配置
 * @returns 验证结果
 */
function validatePipeline(config: PipelineConfig): ValidationResult {
  // 请在此处实现代码
  return { valid: true };
}

questions.reference_solution:
function validatePipeline(config: PipelineConfig): ValidationResult {
  const taskSet = new Set(config.tasks);
  for (const [task, dep] of config.dependencies) {
    if (!taskSet.has(task) || !taskSet.has(dep)) {
      return { valid: false, error: 'Undefined task in dependencies' };
    }
  }
  const graph = new Map();
  config.tasks.forEach(t => graph.set(t, []));
  config.dependencies.forEach(([t, d]) => graph.get(d).push(t));
  const visited = new Set();
  const recStack = new Set();
  function hasCycle(node: string): boolean {
    visited.add(node);
    recStack.add(node);
    for (const next of graph.get(node)) {
      if (!visited.has(next) && hasCycle(next)) return true;
      if (recStack.has(next)) return true;
    }
    recStack.delete(node);
    return false;
  }
  for (const task of config.tasks) {
    if (!visited.has(task) && hasCycle(task)) return { valid: false, error: 'Cycle detected' };
  }
  return { valid: true };
}

