interface Task {
  id: string;
  duration: number;
  dependencies: string[];
}
/**
 * 计算最短完成时间
 * @param tasks - 任务列表
 * @param maxWorkers - 最大并发数
 * @returns 总耗时
 */
function scheduleTasks(tasks: Task[], maxWorkers: number): number {
  // 请在此处实现代码
  return 0;
}

questions.reference_solution:
function scheduleTasks(tasks: Task[], maxWorkers: number): number {
  const map = new Map(tasks.map(t => [t.id, t]));
  const indegree = new Map();
  const graph = new Map();
  tasks.forEach(t => {
    indegree.set(t.id, t.dependencies.length);
    graph.set(t.id, []);
  });
  tasks.forEach(t => t.dependencies.forEach(d => graph.get(d).push(t.id)));
  const ready = tasks.filter(t => indegree.get(t.id) === 0).map(t => ({ ...t, startTime: 0 }));
  const running = [];
  let time = 0;
  while (ready.length || running.length) {
    while (running.length < maxWorkers && ready.length) {
      const task = ready.shift();
      task.startTime = time;
      running.push(task);
    }
    if (!running.length) break;
    running.sort((a, b) => (a.startTime + a.duration) - (b.startTime + b.duration));
    const finished = running.shift();
    time = finished.startTime + finished.duration;
    graph.get(finished.id).forEach(nextId => {
      indegree.set(nextId, indegree.get(nextId) - 1);
      if (indegree.get(nextId) === 0) ready.push({ ...map.get(nextId), startTime: 0 });
    });
  }
  return time;
}

