function hasVersionConflict(deps: Dep[]): boolean {
  const map = new Map<string, Dep[]>();
  deps.forEach(d => {
    if (!map.has(d.pkg)) map.set(d.pkg, []);
    map.get(d.pkg)!.push(d);
  });
  for (const list of map.values()) {
    let maxMin = -1;
    let minMax = Infinity;
    for (const d of list) {
      maxMin = Math.max(maxMin, d.min);
      minMax = Math.min(minMax, d.max);
    }
    if (maxMin > minMax) return true;
  }
  return false;
}

