class TokenBucket {
  capacity: number; rate: number; tokens: number; lastTime: number;
  constructor(capacity: number, rate: number) {
    this.capacity = capacity; this.rate = rate;
    this.tokens = capacity; this.lastTime = Date.now();
  }
  allowRequest(): boolean {
    const now = Date.now();
    const delta = (now - this.lastTime) / 1000 * this.rate;
    this.tokens = Math.min(this.capacity, this.tokens + delta);
    this.lastTime = now;
    if (this.tokens >= 1) { this.tokens--; return true; }
    return false;
  }
}

