questions.reference_solution:
function calculateCriticalPath(stages: Stage[]): number {
  const map = new Map(stages.map(s => [s.id, s]));
  const memo = new Map<string, number>();
  function getFinish(id: string): number {
    if (memo.has(id)) return memo.get(id)!;
    const s = map.get(id)!;
    const maxDep = s.deps.length ? Math.max(...s.deps.map(getFinish)) : 0;
    const res = maxDep + s.duration;
    memo.set(id, res);
    return res;
  }
  return Math.max(...stages.map(s => getFinish(s.id)));
}

