function detectHydrationMismatch(serverHTML: Node, clientDOM: Node, path = ''): string | null {
  if (serverHTML.tag !== clientDOM.tag) return path || '/';
  if (serverHTML.text !== clientDOM.text) return (path || '/') + '/text';
  const sChildren = serverHTML.children || [];
  const cChildren = clientDOM.children || [];
  for (let i = 0; i < Math.max(sChildren.length, cChildren.length); i++) {
    const res = detectHydrationMismatch(sChildren[i], cChildren[i], (path || '/') + '/' + i);
    if (res) return res;
  }
  return null;
}

