function maximizeTasks(tasks: Task[], budget: number): string[] {
  tasks.sort((a, b) => a.tokens - b.tokens);
  const result = [];
  let total = 0;
  for (const t of tasks) {
    if (total + t.tokens <= budget) {
      total += t.tokens;
      result.push(t.id);
    } else break;
  }
